// src/pages/FarmEditPage.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import speciesOptions from '../data/speciesData';

function FarmEditPage() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  // State chính cho toàn bộ form
  const [farmData, setFarmData] = useState({
    tenCoSo: '',
    tinhThanhPho: '',
    xaPhuong: '',
    diaChiCoSo: '',
    vido: '',
    kinhdo: '',
    ngayThanhLap: '',
    giayPhepKinhDoanh: '',
    tenNguoiDaiDien: '',
    namSinh: '',
    soCCCD: '',
    ngayCapCCCD: '',
    noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '',
    diaChiNguoiDaiDien: '',
    mucDichNuoi: '',
    hinhThucNuoi: '',
    maSoCoSoGayNuoi: '',
    tongDan: '',
    loaiHinhKinhDoanhGo: '',
    nganhNgheKinhDoanhGo: '',
    khoiLuong: '',
    loaiCoSoDangKy: '',
    tenLamSan: '',
    tenKhoaHoc: '',
    issueDate: '',
    expiryDate: '',
    trangThai: '',
    ghiChu: '',
  });

  const [loading, setLoading] = useState(true);
  const [errorMessage, setErrorMessage] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  
  // State để điều khiển giao diện chọn/nhập tay
  const [selectedSpecies, setSelectedSpecies] = useState('');
  const [isManualEntry, setIsManualEntry] = useState(false);

  useEffect(() => {
    const fetchFarmData = async () => {
      setLoading(true);
      try {
        const response = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        const data = { ...response.data };

        Object.keys(data).forEach(key => {
          if (['ngayThanhLap', 'ngayCapCCCD', 'issueDate', 'expiryDate'].includes(key) && data[key]) {
            data[key] = new Date(data[key]).toISOString().split('T')[0];
          }
        });
        setFarmData(data);
        
        const existingSpecies = data.tenLamSan;
        const isInOptions = speciesOptions.some(s => s.tenLamSan === existingSpecies || s.tenLamSan === 'Nhập thủ công');

        if (existingSpecies && !isInOptions) {
          setSelectedSpecies('Nhập thủ công');
          setIsManualEntry(true);
        } else {
          setSelectedSpecies(existingSpecies || '');
          setIsManualEntry(false);
        }

      } catch (error) {
        setErrorMessage('Không thể tải dữ liệu cơ sở.');
      } finally {
        setLoading(false);
      }
    };
    if (farmId) fetchFarmData();
  }, [farmId, token]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    if (name === 'speciesSelection') {
      setSelectedSpecies(value);
      if (value === 'Nhập thủ công') {
        setIsManualEntry(true);
        setFarmData(prev => ({ ...prev, tenLamSan: '', tenKhoaHoc: '' }));
      } else {
        setIsManualEntry(false);
        const matched = speciesOptions.find(s => s.tenLamSan === value);
        setFarmData(prev => ({
          ...prev,
          tenLamSan: matched ? matched.tenLamSan : '',
          tenKhoaHoc: matched ? matched.tenKhoaHoc : '',
        }));
      }
    } else {
      setFarmData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrorMessage('');
    setSuccessMessage('');
    try {
      await axios.put(`http://localhost:10000/api/farms/${farmId}`, farmData, {
          headers: { Authorization: `Bearer ${token}` }
      });
      setSuccessMessage('Cập nhật thông tin cơ sở thành công!');
    } catch (error) {
      setErrorMessage(error.response?.data?.message || 'Cập nhật thất bại.');
    }
  };

  if (loading) return <div className="form-container"><p>Đang tải...</p></div>;

  return (
    <div className="form-container">
      <h1>Chỉnh sửa thông tin cơ sở</h1>
      {successMessage && <p className="success-message">{successMessage}</p>}
      {errorMessage && <p className="error-message">{errorMessage}</p>}
      <form onSubmit={handleSubmit}>
        
        {/* === MỤC THÔNG TIN CƠ SỞ === */}
        <section className="khai-bao-section">
          <h3>Thông tin cơ sở</h3>
          {/* Thêm các input cho thông tin cơ sở ở đây */}
          <div className="form-group">
            <label htmlFor="tenCoSo">Tên cơ sở:</label>
            <input type="text" id="tenCoSo" name="tenCoSo" value={farmData.tenCoSo} onChange={handleChange} required />
          </div>
           <div className="form-group">
            <label htmlFor="diaChiCoSo">Địa chỉ cơ sở:</label>
            <input type="text" id="diaChiCoSo" name="diaChiCoSo" value={farmData.diaChiCoSo} onChange={handleChange} required />
          </div>
          {/* ... và các trường khác */}
        </section>

        {/* === MỤC THÔNG TIN NGƯỜI ĐẠI DIỆN === */}
        <section className="khai-bao-section">
          <h3>Thông tin người đại diện</h3>
          {/* Thêm các input cho người đại diện ở đây */}
          <div className="form-group">
            <label htmlFor="tenNguoiDaiDien">Tên người đại diện:</label>
            <input type="text" id="tenNguoiDaiDien" name="tenNguoiDaiDien" value={farmData.tenNguoiDaiDien} onChange={handleChange} required />
          </div>
           <div className="form-group">
            <label htmlFor="soCCCD">Số CCCD:</label>
            <input type="text" id="soCCCD" name="soCCCD" value={farmData.soCCCD} onChange={handleChange} required />
          </div>
          {/* ... và các trường khác */}
        </section>

        {/* === MỤC THÔNG TIN LOÀI (ĐÃ ĐƠN GIẢN HÓA) === */}
        {(farmData.loaiCoSoDangKy) && (
            <section className="khai-bao-section">
                <h3>Thông tin Loài</h3>
                <div className="form-grid">
                    <div className="form-group">
                        <label htmlFor="speciesSelection">Tên lâm sản:</label>
                        <select 
                            id="speciesSelection"
                            name="speciesSelection"
                            value={selectedSpecies}
                            onChange={handleChange}
                        >
                            <option value="">-- Chọn hoặc nhập thủ công --</option>
                            {speciesOptions.map((option, index) => (
                                <option key={index} value={option.tenLamSan}>
                                    {option.tenLamSan}
                                </option>
                            ))}
                        </select>
                    </div>
                    
                    {!isManualEntry && selectedSpecies && selectedSpecies !== 'Nhập thủ công' && (
                        <div className="form-group">
                            <label>Tên khoa học:</label>
                            <input type="text" value={farmData.tenKhoaHoc} readOnly disabled />
                        </div>
                    )}

                    {isManualEntry && (
                        <>
                            <div className="form-group">
                                <label htmlFor="tenLamSan">Tên lâm sản (nhập tay):</label>
                                <input 
                                    type="text" 
                                    id="tenLamSan" 
                                    name="tenLamSan" 
                                    value={farmData.tenLamSan} 
                                    onChange={handleChange} 
                                    placeholder="Nhập tên lâm sản" 
                                    required
                                />
                            </div>
                            <div className="form-group">
                                <label htmlFor="tenKhoaHoc">Tên khoa học (nhập tay):</label>
                                <input 
                                    type="text" 
                                    id="tenKhoaHoc" 
                                    name="tenKhoaHoc" 
                                    value={farmData.tenKhoaHoc} 
                                    onChange={handleChange} 
                                    placeholder="Nhập tên khoa học" 
                                />
                            </div>
                        </>
                    )}
                </div>
            </section>
        )}
        
        {/* ... các section khác (nếu có) ... */}

        <div className="form-actions">
            <button type="submit" className="submit-button">Lưu thay đổi</button>
            <button type="button" onClick={() => navigate(-1)} className="cancel-button">Hủy</button>
        </div>
      </form>
    </div>
  );
}

export default FarmEditPage;
